// A classic mobile-MVC counter, showing where each role's responsibility lies.
import 'package:flutter/material.dart';

// ============ MODEL ============
// Owns the data + business rules. Doesn't know Flutter exists.
class CounterModel {
  int _count = 0;
  int get count => _count;

  // The Model publishes changes via listeners — the classic Observer pattern.
  final _listeners = <VoidCallback>[];
  void addListener(VoidCallback fn) => _listeners.add(fn);
  void removeListener(VoidCallback fn) => _listeners.remove(fn);
  void _notify() { for (final fn in _listeners) fn(); }

  // Business rules
  void increment() { _count++; _notify(); }
  void reset()     { _count = 0; _notify(); }
}

// ============ CONTROLLER ============
// Mediates user input. Decides what happens. Never renders.
class CounterController {
  CounterController(this.model);
  final CounterModel model;

  void onIncrementPressed() {
    // In a real app: validation, logging, analytics — before mutating.
    model.increment();
  }

  void onResetPressed() => model.reset();
}

// ============ VIEW ============
// Renders the model. Passes user input to the controller.
class CounterView extends StatefulWidget {
  const CounterView({super.key});
  @override State<CounterView> createState() => _CounterViewState();
}

class _CounterViewState extends State<CounterView> {
  final _model = CounterModel();
  late final _controller = CounterController(_model);

  @override
  void initState() {
    super.initState();
    _model.addListener(_rebuild);   // View observes Model changes
  }

  @override
  void dispose() {
    _model.removeListener(_rebuild);
    super.dispose();
  }

  void _rebuild() => setState(() {});

  @override
  Widget build(BuildContext context) => Scaffold(
    body: Center(child: Text('${_model.count}',
      style: const TextStyle(fontSize: 40))),
    floatingActionButton: Column(
      mainAxisAlignment: MainAxisAlignment.end,
      children: [
        FloatingActionButton(
          heroTag: 'inc',
          onPressed: _controller.onIncrementPressed,
          child: const Icon(Icons.add),
        ),
        const SizedBox(height: 8),
        FloatingActionButton(
          heroTag: 'reset',
          onPressed: _controller.onResetPressed,
          child: const Icon(Icons.refresh),
        ),
      ],
    ),
  );
}

void main() => runApp(const MaterialApp(home: CounterView()));

// Notice:
//   * Model has NO Flutter imports. It's pure Dart.
//   * View doesn't call model.increment() directly — it goes through Controller.
//   * Controller doesn't render — it just orchestrates.
// This is 'pure' MVC. Compare to modern MVVM (Level 6.2) — very similar in
// structure; the biggest difference is that MVVM's ViewModel exposes
// observable/reactive state, and the View binds to it declaratively.
